select count(*)
from wallet_transaction
where user_id = #{userId}

    and txn_type = #{txnType}


    and create_time >= #{startTime}


    and create_time < #{endTime}

select id, user_id, txn_no, txn_type, biz_type, biz_id, amount, before_balance, after_balance, remark, operator_id, create_time from wallet_transaction where user_id = #{userId}
and txn_type = #{txnType}
and create_time >= #{startTime}
and create_time < #{endTime}
order by create_time desc, id desc limit #{limit} offset #{offset}
